do $$
declare
  child_count int;
  parent_count int;
  set_count int;
  unsupported_finish_count int;
  existing_child_count int;
  id_collision_count int;
begin
  select count(*) into child_count from pkg06f_active_child_printings;
  select count(distinct card_print_id) into parent_count from pkg06f_active_child_printings;
  select count(distinct set_key) into set_count from pkg06f_active_child_printings;
  select count(*) into unsupported_finish_count
  from pkg06f_active_child_printings target
  left join public.finish_keys fk
    on fk.key = target.finish_key
   and fk.is_active = true
  where fk.key is null;
  select count(*) into existing_child_count
  from pkg06f_active_child_printings target
  join public.card_printings cpr
    on cpr.card_print_id = target.card_print_id
   and cpr.finish_key = target.finish_key;
  select count(*) into id_collision_count
  from pkg06f_active_child_printings target
  join public.card_printings cpr on cpr.id = target.card_printing_id;

  if child_count <> 355 then raise exception 'PKG-06F child count drift: %', child_count; end if;
  if parent_count <> 355 then raise exception 'PKG-06F parent count drift: %', parent_count; end if;
  if set_count <> 4 then raise exception 'PKG-06F set count drift: %', set_count; end if;
  if unsupported_finish_count <> 0 then raise exception 'PKG-06F unsupported finish count: %', unsupported_finish_count; end if;
  if existing_child_count <> 0 then raise exception 'PKG-06F existing child count: %', existing_child_count; end if;
  if id_collision_count <> 0 then raise exception 'PKG-06F id collision count: %', id_collision_count; end if;
end $$;

insert into public.card_printings (
  id,
  card_print_id,
  finish_key,
  is_provisional,
  provenance_source,
  provenance_ref,
  created_by
)
select
  card_printing_id,
  card_print_id,
  finish_key,
  false,
  provenance_source,
  provenance_ref,
  created_by
from pkg06f_active_child_printings;

select
  'PKG-06F-ACTIVE-FINISH-CHILD-PRINTING-INSERTS'::text as package_id,
  '27e3873d92679d3255f13f65f90e14597511535a3f4567c89099515ea1ada8f2'::text as source_readiness_fingerprint,
  '795cb07aed903181a3f671c1ad76d55139ca31dcf73c84269a13494d71b25a5f'::text as package_fingerprint,
  (select count(distinct set_key) from pkg06f_active_child_printings)::int as planned_sets,
  (select count(distinct card_print_id) from pkg06f_active_child_printings)::int as target_parent_rows,
  (select count(*) from pkg06f_active_child_printings)::int as planned_child_rows;

rollback;
